import{c as a,Q as t,j as s,m as n}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"OpenClaw — available tools","description":"The 11-tool investor subset bundled with the skill, with command examples.","frontmatter":{"title":"OpenClaw — available tools","description":"The 11-tool investor subset bundled with the skill, with command examples."},"headers":[],"relativePath":"openclaw/tools.md","filePath":"openclaw/tools.md","lastUpdated":1780196777000}'),o={name:"openclaw/tools.md"};function l(i,e,d,p,r,c){return t(),s("div",null,[...e[0]||(e[0]=[n(`<div class="warning custom-block"><p class="custom-block-title">🚧 In development — not in the Testing Guide</p><p>This surface is still being hardened and isn&#39;t part of the <a href="/guide/">Testing Guide</a>. The page below describes the intended design. To evaluate MuHaven today, use <a href="/havenbot/overview">HavenBot</a> or the <a href="/mcp/overview">MCP server</a>.</p></div><h1 id="available-tools" tabindex="-1">Available tools <a class="header-anchor" href="#available-tools" aria-label="Permalink to &quot;Available tools&quot;">​</a></h1><p>The OpenClaw skill bundles a <strong>deliberate subset</strong> of <code>@muhaven/mcp</code> — 11 tools out of 25. The subset is locked at the type level: a <code>verify-subset.ts</code> build gate enforces a three-way consistency check between the skill&#39;s <code>TOOLSET_SUBSET</code> constant, <code>manifest.json#mcp.tool_subset</code>, and <code>SKILL.md</code> frontmatter.</p><p>Every section below shows the bot command you type <strong>and</strong> a representative bot reply, so you can see what to expect before you try it.</p><blockquote><p>Throughout this page, <code>&lt;TOKEN&gt;</code> and <code>RWA1</code> stand in for whichever active RWA token you hold. Your <code>/tokens</code> command lists what&#39;s currently in your catalog.</p></blockquote><h2 id="what-s-included-11-tools" tabindex="-1">What&#39;s included (11 tools) <a class="header-anchor" href="#what-s-included-11-tools" aria-label="Permalink to &quot;What&#39;s included (11 tools)&quot;">​</a></h2><h3 id="read-7-tools" tabindex="-1">Read (7 tools) <a class="header-anchor" href="#read-7-tools" aria-label="Permalink to &quot;Read (7 tools)&quot;">​</a></h3><p>All read tools from <code>@muhaven/mcp</code> are included:</p><table tabindex="0"><thead><tr><th>Tool</th><th>What it does</th></tr></thead><tbody><tr><td><code>muhaven.read.portfolio</code></td><td>Aggregate portfolio summary.</td></tr><tr><td><code>muhaven.read.yields</code></td><td>Per-token yield history.</td></tr><tr><td><code>muhaven.read.distribution</code></td><td>Per-epoch distribution status.</td></tr><tr><td><code>muhaven.read.tokens</code></td><td>RWA tokens you hold.</td></tr><tr><td><code>muhaven.read.audit</code></td><td>Your tiered-autonomy audit log.</td></tr><tr><td><code>muhaven.read.protection_coverage</code></td><td>DefaultProtection coverage for a token.</td></tr><tr><td><code>muhaven.read.kyc_attestation</code></td><td>KYC attestation registry status.</td></tr></tbody></table><p><strong>Example — portfolio + a token-specific yield check:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You → /portfolio</span></span>
<span class="line"><span></span></span>
<span class="line"><span>@muhaven_bot → 🪙 You hold 3 RWA tokens.</span></span>
<span class="line"><span>                  Status: balanced · last sync 09:14 UTC</span></span>
<span class="line"><span>                  (encrypted handles hidden — open the dashboard</span></span>
<span class="line"><span>                   to decrypt locally with your permit)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>You → /yields &lt;TOKEN&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>@muhaven_bot → &lt;TOKEN&gt; yield, last 5 epochs:</span></span>
<span class="line"><span>                  • Epoch 7 — $0.00129 / share (May 15)</span></span>
<span class="line"><span>                  • Epoch 6 — $0.00134 / share (Apr 15)</span></span>
<span class="line"><span>                  • Epoch 5 — $0.00118 / share (Mar 15)</span></span>
<span class="line"><span>                  • Epoch 4 — $0.00120 / share (Feb 15)</span></span>
<span class="line"><span>                  • Epoch 3 — $0.00115 / share (Jan 15)</span></span>
<span class="line"><span>                  Annualized ≈ 1.5%</span></span></code></pre></div><p>Other useful read commands (same shape, different tool):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You → /tokens</span></span>
<span class="line"><span>@muhaven_bot → 3 active RWA tokens: &lt;TOKEN&gt;, RWA1, RWA2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>You → /audit</span></span>
<span class="line"><span>@muhaven_bot → Last 10 audit rows:</span></span>
<span class="line"><span>                  • 11:42 propose_buy &lt;TOKEN&gt; 50 mhUSDC (settled)</span></span>
<span class="line"><span>                  • 11:14 propose_claim &lt;TOKEN&gt; ep5 (settled)</span></span>
<span class="line"><span>                  • ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>You → /protection &lt;TOKEN&gt;</span></span>
<span class="line"><span>@muhaven_bot → &lt;TOKEN&gt; DefaultProtection: active.</span></span>
<span class="line"><span>                  50bps reserve covers ~$250K notional.</span></span></code></pre></div><h3 id="position-2-tools-—-buy-claim-only" tabindex="-1">Position (2 tools — buy + claim only) <a class="header-anchor" href="#position-2-tools-—-buy-claim-only" aria-label="Permalink to &quot;Position (2 tools — buy + claim only)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>What it does</th></tr></thead><tbody><tr><td><code>muhaven.position.buy</code></td><td>Propose a Subscription buy. Tier-gated via OpenClaw three-tier classifier.</td></tr><tr><td><code>muhaven.position.claim</code></td><td>Propose a yield claim for one or more (token, epoch) tuples.</td></tr></tbody></table><p><strong>Example — a sub-$200 buy (tier 1, inline button):</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You → /buy 50 &lt;TOKEN&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>@muhaven_bot → You&#39;re about to buy 50 mhUSDC of &lt;TOKEN&gt;.</span></span>
<span class="line"><span>                  Quote: ~49.85 shares @ NAV $1.003</span></span>
<span class="line"><span>                  Tier:  Inline (≤$200)</span></span>
<span class="line"><span>                  [✅ Confirm]  [❌ Cancel]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>You → (tap ✅ Confirm)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>@muhaven_bot → ✅ Settled. Tx: 0xabc... (View on Arbiscan)</span></span></code></pre></div><p><strong>Example — a claim of a single epoch:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You → /claim &lt;TOKEN&gt; 7</span></span>
<span class="line"><span></span></span>
<span class="line"><span>@muhaven_bot → Claim &lt;TOKEN&gt; yield for epoch 7?</span></span>
<span class="line"><span>                  Estimated payout: $14.20 (encrypted)</span></span>
<span class="line"><span>                  Tier:  Inline (claim is fee-bearing pull)</span></span>
<span class="line"><span>                  [✅ Confirm]  [❌ Cancel]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>You → (tap ✅ Confirm)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>@muhaven_bot → ✅ Claimed. Tx: 0xdef...</span></span></code></pre></div><p>For tier-2 ($200–$5K Mini-App OTP) and tier-3 (&gt;$5K passkey deeplink) buys, the bot replaces the inline button with a Mini App launcher or a dashboard deeplink — see <a href="/openclaw/confirmation-tiers">Three confirmation tiers</a>.</p><h3 id="policy-2-tools-—-pause-status-only" tabindex="-1">Policy (2 tools — pause + status only) <a class="header-anchor" href="#policy-2-tools-—-pause-status-only" aria-label="Permalink to &quot;Policy (2 tools — pause + status only)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool</th><th>What it does</th></tr></thead><tbody><tr><td><code>muhaven.policy.pause</code></td><td>Activate the <code>/pause</code> kill-switch. Always allowed regardless of tier.</td></tr><tr><td><code>muhaven.policy.session_key_status</code></td><td>Inspect the ZeroDev session-key state.</td></tr></tbody></table><p><strong>Example — pause from anywhere:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You → /pause</span></span>
<span class="line"><span></span></span>
<span class="line"><span>@muhaven_bot → ⏸ Agent paused.</span></span>
<span class="line"><span>                  On-chain validator uninstalled in block 8214321.</span></span>
<span class="line"><span>                  All propose tools will return 423 PAUSED.</span></span>
<span class="line"><span>                  To resume, open https://muhaven.app/agent and</span></span>
<span class="line"><span>                  complete the WebAuthn ceremony (Telegram can&#39;t</span></span>
<span class="line"><span>                  drive that — no browser).</span></span></code></pre></div><p><strong>Example — session-key inspection before a big buy:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You → /sessionkey</span></span>
<span class="line"><span></span></span>
<span class="line"><span>@muhaven_bot → Session key:</span></span>
<span class="line"><span>                  • Value cap per call: $5,000</span></span>
<span class="line"><span>                  • Value cap per epoch: $50,000</span></span>
<span class="line"><span>                  • Validity: 42 minutes remaining</span></span>
<span class="line"><span>                  • Target allowlist: 11 MuHaven contracts</span></span>
<span class="line"><span>                  Anything ≤$5K per call signs without re-prompt.</span></span></code></pre></div><h2 id="what-s-deliberately-excluded-11-tools" tabindex="-1">What&#39;s deliberately excluded (11 tools) <a class="header-anchor" href="#what-s-deliberately-excluded-11-tools" aria-label="Permalink to &quot;What&#39;s deliberately excluded (11 tools)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Excluded tool</th><th>Why excluded</th></tr></thead><tbody><tr><td><code>position.sell</code></td><td>Multi-leg redemption queue ceremony doesn&#39;t fit a three-tier Telegram confirmation.</td></tr><tr><td><code>position.rebalance</code></td><td>Multi-leg multicall doesn&#39;t fit a single inline-button confirmation.</td></tr><tr><td><code>policy.set_tier</code></td><td>Tier transitions need the dashboard WebAuthn ceremony (Paused → any).</td></tr><tr><td><code>policy.audit_export</code></td><td>Audit export needs a download surface, not a Telegram message.</td></tr><tr><td><code>issuer.distribute_yield</code></td><td>OpenClaw skill is investor-only.</td></tr><tr><td><code>issuer.kyc_add</code></td><td>Same.</td></tr><tr><td><code>issuer.kyc_remove</code></td><td>Same.</td></tr><tr><td><code>issuer.unpause_token</code></td><td>Same.</td></tr><tr><td><code>issuer.audit_query</code></td><td>Same.</td></tr><tr><td><code>governance.propose</code></td><td>Encrypted-vote ceremony needs the cofhe SDK in a browser.</td></tr><tr><td><code>governance.cast_vote</code></td><td>Same.</td></tr></tbody></table><p>If you need these tools, use <a href="/havenbot/overview">HavenBot</a> or <a href="/mcp/overview"><code>@muhaven/mcp</code></a> on a non-OpenClaw host.</p><h2 id="bot-command-mapping" tabindex="-1">Bot command mapping <a class="header-anchor" href="#bot-command-mapping" aria-label="Permalink to &quot;Bot command mapping&quot;">​</a></h2><p>When you interact with the Telegram bot, commands route to MCP tools as follows:</p><table tabindex="0"><thead><tr><th>Bot command</th><th>MCP tool</th></tr></thead><tbody><tr><td><code>/portfolio</code></td><td><code>muhaven.read.portfolio</code></td></tr><tr><td><code>/yields &lt;token&gt;</code></td><td><code>muhaven.read.yields</code></td></tr><tr><td><code>/distribution &lt;token&gt; &lt;epoch&gt;</code></td><td><code>muhaven.read.distribution</code></td></tr><tr><td><code>/tokens</code></td><td><code>muhaven.read.tokens</code></td></tr><tr><td><code>/audit</code></td><td><code>muhaven.read.audit</code></td></tr><tr><td><code>/protection &lt;token&gt;</code></td><td><code>muhaven.read.protection_coverage</code></td></tr><tr><td><code>/kyc &lt;token&gt; &lt;address&gt;</code></td><td><code>muhaven.read.kyc_attestation</code></td></tr><tr><td><code>/buy &lt;amount&gt; &lt;token&gt;</code></td><td><code>muhaven.position.buy</code> (with tier classifier)</td></tr><tr><td><code>/claim &lt;token&gt; &lt;epoch&gt;</code></td><td><code>muhaven.position.claim</code> (with tier classifier)</td></tr><tr><td><code>/pause</code></td><td><code>muhaven.policy.pause</code></td></tr><tr><td><code>/sessionkey</code></td><td><code>muhaven.policy.session_key_status</code></td></tr></tbody></table><h2 id="why-a-subset" tabindex="-1">Why a subset? <a class="header-anchor" href="#why-a-subset" aria-label="Permalink to &quot;Why a subset?&quot;">​</a></h2><p>Three reasons:</p><ol><li><strong>Phone-first UX assumptions don&#39;t match every tool.</strong> Multi-leg ceremonies (sell, rebalance, distribute_yield) and ceremony-gated tools (set_tier, governance) need a browser surface.</li><li><strong>Investor-only on Telegram.</strong> Issuer flows have stricter trust assumptions (issuer&#39;s MuHaven wallet signing) and benefit from the dashboard&#39;s full audit copilot rendering. They&#39;re available on HavenBot and MCP instead.</li><li><strong>Smaller attack surface.</strong> The OpenClaw skill runs as a sandboxed binary with declared egress allowlist. The fewer tools in the catalog, the smaller the prompt-injection attack surface.</li></ol><h2 id="how-the-subset-is-enforced" tabindex="-1">How the subset is enforced <a class="header-anchor" href="#how-the-subset-is-enforced" aria-label="Permalink to &quot;How the subset is enforced&quot;">​</a></h2><p>The skill&#39;s <code>src/index.ts</code> calls <code>runMcpStdioCli({ filterRegistry })</code> from <code>@muhaven/mcp/server.ts</code>. The filter is a synchronous callback that:</p><ol><li>Receives the full 25-tool registry from the bundled MCP server.</li><li>Returns only the 11 tools in the <code>TOOLSET_SUBSET</code> set.</li><li>Refuses to start if the filtered registry is empty (sanity check against a typo&#39;d subset).</li></ol><p>The hash verification gate fires <strong>before</strong> the filter — so an attacker who patched a single descriptor cannot hide it by shipping a subset filter that excludes the patched tool. The descriptor is verified, <em>then</em> filtered. This is documented in <code>packages/openclaw-skill/src/index.ts</code> NatSpec.</p><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/openclaw/playbook">Playbook — phone-first scenarios</a> — full chat flows for commuting, claiming from bed, switching tiers on the train.</li><li><a href="/openclaw/telegram-bot">Telegram bot</a> — the commands above in context.</li><li><a href="/openclaw/confirmation-tiers">Three confirmation tiers</a> — how the tier classifier wraps each propose call.</li><li><a href="/openclaw/troubleshooting">Troubleshooting</a> — common skill + bot issues.</li></ul>`,41)])])}const m=a(o,[["render",l]]);export{u as __pageData,m as default};
